SELECT p.product_id AS productId, p.product_name AS productName, p.price AS price, p.img_url AS imgUrl, p.is_best AS best, p.category_id AS categoryId, p.category_detail_id AS categoryDetailId, p.quick_rundown AS quickRundown FROM product_tb p
p.product_name LIKE CONCAT('%', #{req.keyword}, '%')
AND p.category_id = #{req.categoryId}
AND p.category_detail_id = #{req.categoryDetailId}
AND p.is_best = #{req.best}
ORDER BY p.price ASC
ORDER BY p.price DESC
ORDER BY p.created_at ASC
ORDER BY p.created_at DESC

